#include <bits/stdc++.h>
using namespace std;
int n,a,ans;
vector<int> v;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a);
        if(i==1){
            v.push_back(a);
            ans=a;
            continue;
        }
        int b=lower_bound(v.begin(),v.end(),a)-v.begin(),s=lower_bound(v.begin(),v.end(),a)-v.begin()-1;
    	if(s==-1)
    		s=v.size();
        /*for(int i=0;i<v.size();i++)
        	printf("%d ",v[i]);
        printf("\n");
        printf("%d %d %d\n",v[s],v[b],ans);*/
		if(b==v.size())
            ans+=a-v[s];
        else if(s==v.size())
            ans+=v[b]-a;
        else
            ans+=min(v[b]-a,a-v[s]);
        v.insert(b+v.begin(),a);
    }
    printf("%d",ans);
    return 0;
}
